import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, UpdateResult, DeleteResult } from 'typeorm';
import { UserEntity as User, UserEntity } from './../entities';
import { Pagination, PaginationOptionsInterface } from './../paginate';
import { UserModel } from 'models';
import * as bcrypt from 'bcrypt';
import { InjectConfig, ConfigService } from 'nestjs-config';

@Injectable()
export class UserService {
  private saltRounds: number;

  constructor(
    @InjectRepository(User) private readonly userRepository: Repository<User>,
    @InjectConfig() private readonly config: ConfigService,
  ) {
    this.saltRounds = config.get('app.salt_rounds', 10);
  }

  async paginate(
    options: PaginationOptionsInterface,
  ): Promise<Pagination<User>> {
    const [results, total] = await this.userRepository.findAndCount({
      take: options.limit,
      skip: options.page, // think this needs to be page * limit
    });

    // TODO add more tests for paginate

    return new Pagination<User>({
      results,
      total,
    });
  }

  async create(user: UserModel): Promise<User> {
    user.password = await this.getHash(user.password);

    const result = await this.userRepository.save(
      this.userRepository.create(user),
    );

    delete result.password;
    return result;
  }

  async update(user: UserEntity): Promise<UpdateResult> {
    return await this.userRepository.update(user.id, user);
  }

  async findByEmail(email: string): Promise<User | null> {
    return await this.userRepository.findOne({
      where: {
        email,
      },
    });
  }

  async findById(id: number): Promise<UserEntity | null> {
    return await this.userRepository.findOneOrFail(id);
  }

  async getHash(password: string): Promise<string> {
    return await bcrypt.hash(password, this.saltRounds);
  }

  async compareHash(password: string, hash: string): Promise<boolean> {
    return await bcrypt.compare(password, hash);
  }

  async findByEmailWithPassword(email: string): Promise<User> | null {
    return await this.userRepository.findOne(
      {
        email,
      },
      {
        select: ['email', 'password'],
      },
    );
  }

  async destroy(id: number): Promise<DeleteResult> {
    return await this.userRepository.delete(id);
  }
}

import type { Type } from '@nestjs/common'

import {
  Body,
  Controller,
  Delete,
  Get,
  Patch,
  Post,
  Put,
  Query,
} from '@nestjs/common'
import { ApiBody, IntersectionType, PartialType } from '@nestjs/swagger'
import { upperFirst } from 'lodash'
import pluralize from 'pluralize'

import { ApiResult } from '~/common/decorators/api-result.decorator'
import { IdParam } from '~/common/decorators/id-param.decorator'
import { PagerDto } from '~/common/dto/pager.dto'

import { BaseService } from './base.service'

export function BaseCrudFactory<
  E extends new (...args: any[]) => any,
>({ entity, dto, permissions }: { entity: E, dto?: Type<any>, permissions?: Record<string, string> }): Type<any> {
  const prefix = entity.name.toLowerCase().replace(/entity$/, '')
  const pluralizeName = pluralize(prefix) as string

  dto = dto ?? class extends entity {}

  class Dto extends dto {
    static readonly name = upperFirst(`${pluralizeName}Dto`)
  }
  class UpdateDto extends PartialType(Dto) {
    static readonly name = upperFirst(`${pluralizeName}UpdateDto`)
  }
  class QueryDto extends IntersectionType(PagerDto, PartialType(Dto)) {
    static readonly name = upperFirst(`${pluralizeName}QueryDto`)
  }

  permissions = permissions ?? {
    LIST: `${prefix}:list`,
    CREATE: `${prefix}:create`,
    READ: `${prefix}:read`,
    UPDATE: `${prefix}:update`,
    DELETE: `${prefix}:delete`,
  } as const

  @Controller(pluralizeName)
  class BaseController<S extends BaseService<E>> {
    constructor(private service: S) { }

    @Get()
    @ApiResult({ type: [entity], isPage: true })
    async list(@Query() pager: QueryDto) {
      return await this.service.list(pager)
    }

    @Get(':id')
    @ApiResult({ type: entity })
    async get(@IdParam() id: number) {
      return await this.service.findOne(id)
    }

    @Post()
    @ApiBody({ type: dto })
    async create(@Body() dto: Dto) {
      return await this.service.create(dto)
    }

    @Put(':id')
    async update(@IdParam() id: number, @Body() dto: UpdateDto) {
      return await this.service.update(id, dto)
    }

    @Patch(':id')
    async patch(@IdParam() id: number, @Body() dto: UpdateDto) {
      await this.service.update(id, dto)
    }

    @Delete(':id')
    async delete(@IdParam() id: number) {
      await this.service.delete(id)
    }
  }

  return BaseController
}

import { Resolver, Query, Mutation, Args } from '@nestjs/graphql'
import { getMongoRepository } from 'typeorm'

import { Permission } from '@entities'
import { ApolloError } from 'apollo-server-core'
import { PermissionInput } from '../generator/graphql.schema'

@Resolver('Permission')
export class PermissionResolver {
	@Query()
	async permissions(): Promise<Permission[]> {
		return getMongoRepository(Permission).find({
			where: { isActive: true },
			cache: true
		})
	}

	@Mutation()
	async createPermission(
		@Args('input') input: PermissionInput
	): Promise<boolean> {
		try {
			const data = await getMongoRepository(Permission).findOne({
				code: input.code,
				isActive: true
			})
			if (!data) {
				return (await getMongoRepository(Permission).save(
					new Permission({ ...input })
				))
					? true
					: false
			} else {
				return false
			}
		} catch (error) {
			throw new ApolloError(error)
		}
	}

	@Mutation()
	async updatePermission(
		@Args('id') id: string,
		@Args('input') input: PermissionInput
	): Promise<boolean> {
		try {
			const permission = await getMongoRepository(Permission).findOne({
				_id: id,
				isActive: true
			})
			if (permission) {
				const data = await getMongoRepository(Permission).findOne({
					code: input.code,
					isActive: true
				})
				if (!data || data._id === id) {
					return (await getMongoRepository(Permission).save(
						new Permission({ ...permission, ...input })
					))
						? true
						: false
				} else {
					return false
				}
			} else {
				return false
			}
		} catch (error) {
			throw new ApolloError(error)
		}
	}

	@Mutation()
	async deletePermission(@Args('id') id: string) {
		try {
			const data = await getMongoRepository(Permission).findOne({ _id: id })
			if (data) {
				return (await getMongoRepository(Permission).save(
					new Permission({ ...data, isActive: false })
				))
					? true
					: false
			} else {
				return false
			}
		} catch (error) {
			throw new ApolloError(error)
		}
	}
}

import { CommandHandler, EventBus, ICommandHandler } from '@nestjs/cqrs';
import { TenantRepository } from '@ultimatebackend/repository';
import {
  AcceptMemberInvitationResponse,
  Member,
} from '@ultimatebackend/proto-schema/tenant';
import { AcceptInvitationCommand } from '../../impl';
import { RolesRpcClientService } from '@ultimatebackend/core';
import { JwtService } from '@nestjs/jwt';
import { RpcException } from '@nestjs/microservices';
import { InvitationStatus } from '@ultimatebackend/contracts';
import { Logger } from '@nestjs/common';

@CommandHandler(AcceptInvitationCommand)
export class AcceptInvitationHandler
  implements ICommandHandler<AcceptInvitationCommand> {
  logger = new Logger(this.constructor.name);

  constructor(
    private readonly tenantRepository: TenantRepository,
    private readonly eventBus: EventBus,
    private readonly roleService: RolesRpcClientService,
    private readonly jwtService: JwtService,
  ) {}

  async execute(
    command: AcceptInvitationCommand,
  ): Promise<AcceptMemberInvitationResponse> {
    this.logger.log(`'Async '${command.constructor.name}...`);
    const { input, user } = command;

    try {
      // @ts-ignore
      const payload: {
        tenantId: string;
        memberId: string;
      } = await this.jwtService.decode(input.token);
      if (!payload) {
        throw new RpcException('Invalid invitation token');
      }

      const tenant = await this.tenantRepository.findOneAndUpdate({
        conditions: {
          normalizedName: payload.tenantId,
          member: {
            $elemMatch: {
              id: payload.memberId,
              status: InvitationStatus.PENDING,
            },
          },
        },
        updates: {
          $set: {
            'members.$.status': InvitationStatus.ACCEPTED,
          },
        },
      });

      if (!tenant) {
        throw new RpcException('Invitation for tenant not found');
      }
      const member = tenant.members.reduce(
        (previousValue) =>
          previousValue.id === payload.memberId && previousValue,
      );

      await this.roleService.svc
        .addUserToRole({
          role: member.role,
          domain: tenant.normalizedName,
          actor: 'user',
          userId: user.id.toString(),
        })
        .toPromise();

      return {
        member: (member as unknown) as Member,
      };
    } catch (e) {
      this.logger.error(e);
      throw new RpcException(e);
    }
  }
}

import {
  METHOD_METADATA,
  PATH_METADATA,
  VERSION_METADATA,
} from '@nestjs/common/constants';
import { RequestMethod } from '@nestjs/common/enums';
import { Controller } from '@nestjs/common/interfaces/controllers/controller.interface';
import { VersionValue } from '@nestjs/common/interfaces/version-options.interface';
import {
  addLeadingSlash,
  isString,
  isUndefined,
} from '@nestjs/common/utils/shared.utils';
import { MetadataScanner } from '../metadata-scanner';
import { RouterProxyCallback } from './router-proxy';

export interface RouteDefinition {
  path: string[];
  requestMethod: RequestMethod;
  targetCallback: RouterProxyCallback;
  methodName: string;
  version?: VersionValue;
}

export class PathsExplorer {
  constructor(private readonly metadataScanner: MetadataScanner) {}

  public scanForPaths(
    instance: Controller,
    prototype?: object,
  ): RouteDefinition[] {
    const instancePrototype = isUndefined(prototype)
      ? Object.getPrototypeOf(instance)
      : prototype;

    return this.metadataScanner
      .getAllMethodNames(instancePrototype)
      .reduce((acc, method) => {
        const route = this.exploreMethodMetadata(
          instance,
          instancePrototype,
          method,
        );

        if (route) {
          acc.push(route);
        }

        return acc;
      }, [] as RouteDefinition[]);
  }

  public exploreMethodMetadata(
    instance: Controller,
    prototype: object,
    methodName: string,
  ): RouteDefinition | null {
    const instanceCallback = instance[methodName];
    const prototypeCallback = prototype[methodName];
    const routePath = Reflect.getMetadata(PATH_METADATA, prototypeCallback);
    if (isUndefined(routePath)) {
      return null;
    }
    const requestMethod: RequestMethod = Reflect.getMetadata(
      METHOD_METADATA,
      prototypeCallback,
    );
    const version: VersionValue | undefined = Reflect.getMetadata(
      VERSION_METADATA,
      prototypeCallback,
    );
    const path = isString(routePath)
      ? [addLeadingSlash(routePath)]
      : routePath.map((p: string) => addLeadingSlash(p));

    return {
      path,
      requestMethod,
      targetCallback: instanceCallback,
      methodName,
      version,
    };
  }
}

import {
  WebSocketGateway,
  SubscribeMessage,
  WsResponse,
  WebSocketServer,
  OnGatewayConnection,
  OnGatewayDisconnect
} from '@nestjs/websockets';
import { Observable } from 'rxjs';

import { JwtService } from '../auth/jwt/jwt.service';
import { User } from '../users/interfaces/user.interface';
import { RoomsService } from '../rooms/rooms.service';

@WebSocketGateway(1080, { namespace: 'rooms' })
export class ChatGateway implements OnGatewayConnection, OnGatewayDisconnect {
  @WebSocketServer()
  server;

  connectedUsers: string[] = [];

  constructor(
    private jwtService: JwtService,
    private roomService: RoomsService
  ) {}

  async handleConnection(socket) {
    const user: User = await this.jwtService.verify(
      socket.handshake.query.token,
      true
    );

    this.connectedUsers = [...this.connectedUsers, String(user._id)];

    // Send list of connected users
    this.server.emit('users', this.connectedUsers);
  }

  async handleDisconnect(socket) {
    const user: User = await this.jwtService.verify(
      socket.handshake.query.token,
      true
    );
    const userPos = this.connectedUsers.indexOf(String(user._id));

    if (userPos > -1) {
      this.connectedUsers = [
        ...this.connectedUsers.slice(0, userPos),
        ...this.connectedUsers.slice(userPos + 1)
      ];
    }

    // Sends the new list of connected users
    this.server.emit('users', this.connectedUsers);
  }

  @SubscribeMessage('message')
  async onMessage(client, data: any) {
    const event: string = 'message';
    const result = data[0];

    await this.roomService.addMessage(result.message, result.room);
    client.broadcast.to(result.room).emit(event, result.message);

    return Observable.create(observer =>
      observer.next({ event, data: result.message })
    );
  }

  @SubscribeMessage('join')
  async onRoomJoin(client, data: any): Promise<any> {
    client.join(data[0]);

    const messages = await this.roomService.findMessages(data, 25);

    // Send last messages to the connected user
    client.emit('message', messages);
  }

  @SubscribeMessage('leave')
  onRoomLeave(client, data: any): void {
    client.leave(data[0]);
  }
}

import {
