import {
  Body,
  Controller,
  FileTypeValidator,
  ParseFilePipe,
  Post,
  UploadedFile,
  UseInterceptors,
} from '@nestjs/common';
import {
  ApiBody,
  ApiConsumes,
  ApiCreatedResponse,
  ApiForbiddenResponse,
  ApiTags,
  ApiUnauthorizedResponse,
} from '@nestjs/swagger';
import { Roles } from '../auth/decorators/roles.decorator';
import { Role } from '../users/models/role.enum';
import { ImportService } from './import.service';
import { FileInterceptor } from '@nestjs/platform-express';
import * as multer from 'multer';
import { ImportDto } from './dto/import.dto';
import { ImportStatus } from './models/import-status.interface';

@ApiTags('import-export')
@Controller('import')
@Roles(Role.Admin)
@ApiUnauthorizedResponse({ description: 'User is not logged in' })
@ApiForbiddenResponse({ description: 'User is not admin' })
export class ImportController {
  constructor(private importService: ImportService) {}

  @Post('')
  @ApiBody({
    schema: {
      type: 'object',
      properties: {
        file: {
          type: 'string',
          format: 'binary',
        },
        clear: {
          type: 'string',
          nullable: true,
        },
        noImport: {
          type: 'string',
          nullable: true,
        },
      },
    },
  })
  @ApiConsumes('multipart/form-data')
  @UseInterceptors(
    FileInterceptor('file', {
      storage: multer.memoryStorage(),
    }),
  )
  @ApiCreatedResponse({
    type: ImportStatus,
    description: 'Import status',
  })
  async import(
    @UploadedFile(
      new ParseFilePipe({
        validators: [
          new FileTypeValidator({
            fileType: /(^application\/json$)|(^application\/(x-)?gzip$)/,
          }),
        ],
      }),
    )
    file: Express.Multer.File,
    @Body() data: ImportDto,
  ) {
    return await this.importService.import(
      file.buffer,
      file.mimetype,
      data.clear === 'true',
      data.noImport === 'true',
    );
  }
}

import {
  AfterUpdate,
  BeforeInsert,
  DataSource,
  EntitySubscriberInterface,
  EventSubscriber,
  InsertEvent,
  UpdateEvent,
} from 'typeorm';
import { Order } from './models/order.entity';
import { ProductsService } from '../../catalog/products/products.service';
import { OrderItem } from './models/order-item.entity';
import { OrderStatus } from './models/order-status.enum';

@EventSubscriber()
export class OrdersSubscriber implements EntitySubscriberInterface<Order> {
  constructor(
    dataSource: DataSource,
    private productsService: ProductsService,
  ) {
    dataSource.subscribers.push(this);
  }

  listenTo() {
    return Order;
  }

  @BeforeInsert()
  async beforeInsert(event: InsertEvent<Order>) {
    if (!(await this.productsService.checkProductsStocks(event.entity.items))) {
      event.entity.status = OrderStatus.Failed;
      return;
    }
    await this.productsService.updateProductsStocks(
      'subtract',
      event.entity.items,
    );
  }

  @AfterUpdate()
  async afterUpdate(event: UpdateEvent<Order>) {
    if (!event.entity) {
      return;
    }
    if (
      event.databaseEntity.items.map((i) => i.id).join(',') !==
      event.entity.items.map((i: OrderItem) => i.id).join(',')
    ) {
      if (
        !(await this.productsService.checkProductsStocks(event.entity.items))
      ) {
        event.entity.status = OrderStatus.Failed;
        return;
      }
      await this.productsService.updateProductsStocks(
        'subtract',
        event.entity.items,
      );
    }
    if (
      ['pending', 'confirmed', 'open', 'delivered'].includes(
        event.databaseEntity.status,
      ) &&
      ['failed', 'cancelled', 'refunded'].includes(event.entity.status)
    ) {
      await this.productsService.updateProductsStocks(
        'add',
        event.entity.items,
      );
    }
    if (
      ['failed', 'cancelled', 'refunded'].includes(
        event.databaseEntity.status,
      ) &&
      ['pending', 'confirmed', 'open', 'delivered'].includes(
        event.entity.status,
      )
    ) {
      if (
        !(await this.productsService.checkProductsStocks(event.entity.items))
      ) {
        event.entity.status = OrderStatus.Failed;
        return;
      }
      await this.productsService.updateProductsStocks(
        'subtract',
        event.entity.items,
      );
    }
  }
}

import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Return } from './models/return.entity';
import { Repository } from 'typeorm';
import { ReturnCreateDto } from './dto/return-create.dto';
import { ReturnUpdateDto } from './dto/return-update.dto';
import { NotFoundError } from '../../errors/not-found.error';
import { ConflictError } from '../../errors/conflict.error';
import { OrdersService } from '../orders/orders.service';

@Injectable()
export class ReturnsService {
  constructor(
    @InjectRepository(Return)
    private readonly returnsRepository: Repository<Return>,
    private ordersService: OrdersService,
  ) {}

  async getReturns(): Promise<Return[]> {
    return this.returnsRepository.find({
      relations: ['order', 'order.items'],
    });
  }

  async getReturn(id: number): Promise<Return> {
    const foundReturn = await this.returnsRepository.findOne({
      where: { id },
      relations: [
        'order',
        'order.user',
        'order.items',
        'order.items.product',
        'order.delivery',
        'order.payment',
      ],
    });
    if (!foundReturn) {
      throw new NotFoundError('return', 'id', id.toString());
    }
    return foundReturn;
  }

  async checkReturnUser(userId: number, id: number): Promise<boolean> {
    const foundReturn = await this.returnsRepository.findOne({
      where: { id, order: { user: { id: userId } } },
      relations: ['order', 'order.user'],
    });
    return !!foundReturn;
  }

  async createReturn(
    returnDto: ReturnCreateDto,
    ignoreSubscribers = false,
  ): Promise<Return> {
    const newReturn = new Return();
    const order = await this.ordersService.getOrder(returnDto.orderId);
    try {
      newReturn.order = order;
      newReturn.message = returnDto.message;
      return await this.returnsRepository.save(newReturn, {
        listeners: !ignoreSubscribers,
      });
    } catch (e) {
      throw new ConflictError('return');
    }
  }

  async updateReturn(
    id: number,
    returnDto: ReturnUpdateDto,
    ignoreSubscribers = false,
  ): Promise<Return> {
    const foundReturn = await this.getReturn(id);
    Object.assign(foundReturn, returnDto);
    return this.returnsRepository.save(foundReturn, {
      listeners: !ignoreSubscribers,
    });
  }

  async deleteReturn(id: number): Promise<boolean> {
    await this.getReturn(id);
    await this.returnsRepository.delete({ id });
    return true;
  }
}

