import { Injectable } from '@nestjs/common';
import { PrismaService } from '../common/prisma.service';
import { TenantContextService } from '../common/tenant-context/tenant-context.service';
import { DEFAULT_PLAN_LIMITS } from './interfaces/quota-checker.interface';

@Injectable()
export class BillingService {
  constructor(
    private readonly prisma: PrismaService,
    private readonly tenantContext: TenantContextService,
  ) {}

  async getTenantPlan(tenantId: string) {
    const tenant = await this.prisma.tenant.findUnique({
      where: { id: tenantId },
      select: { id: true, plan: true, status: true },
    });
    return tenant;
  }

  async getPlanLimits(tenantId: string) {
    const tenant = await this.getTenantPlan(tenantId);
    if (!tenant) {
      return null;
    }
    const plan = tenant.plan as 'FREE' | 'PRO';
    return DEFAULT_PLAN_LIMITS[plan];
  }

  async checkQuota(tenantId: string, resource: string) {
    const limits = await this.getPlanLimits(tenantId);
    if (!limits || !(resource in limits)) {
      return { allowed: true, current: 0, limit: Infinity };
    }

    const limit = limits[resource];
    const current = await this.getCurrentUsage(tenantId, resource);

    return {
      allowed: current < limit,
      current,
      limit,
      message: current >= limit ? `${resource} limit reached for your plan` : undefined,
    };
  }

  async getCurrentUsage(tenantId: string, resource: string): Promise<number> {
    // Example implementation - customize per resource type
    switch (resource) {
      case 'members':
        return this.prisma.membership.count({ where: { tenantId } });
      default:
        return 0;
    }
  }

  async upgradePlan(tenantId: string, plan: 'FREE' | 'PRO') {
    // In production, this would integrate with BillingProvider
    return this.prisma.tenant.update({
      where: { id: tenantId },
      data: { plan },
    });
  }

  async getBillingOverview(tenantId: string) {
    const tenant = await this.getTenantPlan(tenantId);
    const limits = await this.getPlanLimits(tenantId);
    const memberCount = await this.prisma.membership.count({ where: { tenantId } });

    return {
      plan: tenant?.plan,
      status: tenant?.status,
      usage: {
        members: {
          current: memberCount,
          limit: limits?.members ?? Infinity,
        },
      },
    };
  }
}

import { INestApplication, Logger } from '@nestjs/common';
import * as session from 'express-session';
import * as passport from 'passport';
import * as redis from 'redis';
import * as useragent from 'express-useragent';
import * as cookieParser from 'cookie-parser';
import * as connectRedis from 'connect-redis';
import { Express } from 'express';
import { NestCloud } from '@nestcloud/core';

const parseIsoDuration = require('parse-iso-duration');

const RedisStore = connectRedis(session);
const passportMiddleware = passport.initialize();
const passportSessionMiddleware = passport.session();

export function authSetup(
  app: INestApplication | Express,
  withPassport: boolean = true,
) {
  try {
    const redisConfig: redis.RedisOptions = NestCloud.global.boot.get(
      'redis',
      {},
    );
    const authConfig: {
      sessionKey?: string;
      sessionSecret?: string;
      domain?: string;
      resave?: boolean;
      rolling?: boolean;
      saveUninitialized?: boolean;
      cookieMaxAge?: string;
      secure?: boolean;
    } = NestCloud.global.boot.get('app.auth', {});

    if (redisConfig?.password === '') {
      delete redisConfig.password;
    }

    // redis init
    const redisClient = redis.createClient({
      ...redisConfig,
    });

    const store = new RedisStore({ client: redisClient });

    // sessions
    const sessionMiddleware = session({
      secret: authConfig.sessionSecret,
      resave: Boolean(authConfig?.resave),
      rolling: Boolean(authConfig?.rolling),
      saveUninitialized: false,
      cookie: {
        maxAge: parseIsoDuration('PT' + authConfig.cookieMaxAge),
        secure: Boolean(authConfig?.secure),
        domain: authConfig?.domain,
      },
      // proxy: withPassport === true ? undefined : true,
      store,
      name: authConfig.sessionKey,
    });

    if (withPassport) {
      // @ts-ignore
      // app.set('trust proxy', 1);
      app.use(sessionMiddleware);
      app.use(useragent.express());
      app.use(passportMiddleware);
      app.use(passportSessionMiddleware);
    } else {
      app.use(cookieParser());
    }

    // @ts-ignore
    app.set('subdomain offset', 1); // Enable sub domain in app
  } catch (e) {
    Logger.log(e, 'auth.setup');
  }
}

import {
  DNSHealthIndicator,
  MicroserviceHealthIndicator,
  TerminusEndpoint,
  TerminusModuleOptions,
  TerminusOptionsFactory,
} from '@nestjs/terminus';
import { Injectable, Logger } from '@nestjs/common';
import { MongoHealthIndicator } from '../';
import { Transport } from '@nestjs/microservices';

@Injectable()
export class BaseHealthService implements TerminusOptionsFactory {
  private dns: DNSHealthIndicator;
  private ms: MicroserviceHealthIndicator;
  private mongo: MongoHealthIndicator;
  private options: BaseHealthServiceOptions;
  private logger = new Logger(this.constructor.name);

  constructor(
    dns: DNSHealthIndicator,
    ms: MicroserviceHealthIndicator,
    mongo: MongoHealthIndicator,
    options?: BaseHealthServiceOptions,
  ) {
    this.dns = dns;
    this.ms = ms;
    this.mongo = mongo;
    this.options = options;
  }

  async createTerminusOptions(): Promise<TerminusModuleOptions> {
    try {
      const healths = [];

      for (const s of this.options.services) {
        const res = async () =>
          this.ms.pingCheck('tcp', {
            options: {
              host: s.host,
              port: s.port,
              name: s.name,
            },
            // @ts-ignore
            transport: s.transport || Transport.TCP,
          });
        healths.push(res);
      }

      const healthEndpoint: TerminusEndpoint = {
        url: '/health',
        healthIndicators: [
          ...healths,
          async () => this.mongo.pingCheck('mongo'),
        ],
      };
      return {
        endpoints: [healthEndpoint],
      };
    } catch (e) {
      this.logger.error(e);

      const healthEndpoint: TerminusEndpoint = {
        url: '/health',
        healthIndicators: [
          async () => this.dns.pingCheck('google', 'https://google.com'),
        ],
      };

      return {
        endpoints: [healthEndpoint],
      };
    }
  }
}

interface BaseHealthServiceOptions {
  services: ServiceOptions[];
}

interface ServiceOptions {
  port?: number;
  host?: string;
  name?: string;
  transport?: Transport;
}

